def check_ruc(s: str) -> str:
    if not s or not s.isdigit() or len(s) != 11:
        raise ValueError(f"ruc inválido: {s!r}")
    return s

ok = []
for val, bad in [("20123456789", False), ("123", True), ("", True), ("abcdefghijk", True)]:
